-- Generated from Kid City CRM Database.xlsx
-- Source sheets used: users, locations, leads

begin;

create extension if not exists pgcrypto;

drop view if exists public.crm_messages_expanded;
drop view if exists public.crm_tours_expanded;
drop view if exists public.crm_leads_expanded;

drop table if exists public.parent_messages cascade;
drop table if exists public.tours cascade;
drop table if exists public.staff_assignments cascade;
drop table if exists public.classrooms cascade;
drop table if exists public.compliance_items cascade;
drop table if exists public.leads cascade;
drop table if exists public.profiles cascade;
drop table if exists public.locations cascade;

create table public.locations (
  id uuid primary key,
  crm_location_id text not null unique,
  name text not null,
  code text not null unique,
  city text,
  state text,
  address_line1 text,
  address_line2 text,
  postal_code text,
  phone text,
  description text,
  website_url text,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table public.profiles (
  id uuid primary key,
  email text not null unique,
  full_name text,
  role text not null default 'director' check (role in ('executive', 'director', 'admissions', 'billing')),
  location_id uuid references public.locations(id) on delete set null,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table public.leads (
  id uuid primary key,
  location_id uuid references public.locations(id) on delete set null,
  crm_location_id text,
  family_name text not null,
  child_name text,
  child_age integer,
  email text,
  phone text,
  source text,
  status text not null default 'new'
    check (status in ('new', 'contacted', 'tour_scheduled', 'application_started', 'enrolled', 'lost')),
  status_raw text,
  pipeline_stage_raw text,
  intent_score integer,
  notes text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  created_by uuid references public.profiles(id) on delete set null
);

create table public.tours (
  id uuid primary key default gen_random_uuid(),
  created_at timestamptz not null default now(),
  scheduled_at timestamptz,
  lead_id uuid references public.leads(id) on delete cascade,
  family_name text,
  child_name text,
  location_id uuid references public.locations(id) on delete set null,
  status text default 'scheduled',
  notes text
);

create table public.parent_messages (
  id uuid primary key default gen_random_uuid(),
  created_at timestamptz not null default now(),
  lead_id uuid references public.leads(id) on delete cascade,
  family_name text,
  sender_name text,
  channel text default 'email',
  body text,
  location_id uuid references public.locations(id) on delete set null,
  requires_reply boolean not null default false,
  is_unread boolean not null default true
);

create table public.classrooms (
  id uuid primary key default gen_random_uuid(),
  name text,
  classroom_name text,
  age_group text,
  capacity integer,
  location_id uuid references public.locations(id) on delete set null,
  is_active boolean not null default true
);

create table public.staff_assignments (
  id uuid primary key default gen_random_uuid(),
  created_at timestamptz not null default now(),
  full_name text,
  name text,
  role text,
  role_name text,
  classroom_name text,
  shift_start timestamptz,
  location_id uuid references public.locations(id) on delete set null
);

create table public.compliance_items (
  id uuid primary key default gen_random_uuid(),
  created_at timestamptz not null default now(),
  title text,
  detail text,
  notes text,
  due_date date,
  status text,
  location_id uuid references public.locations(id) on delete set null
);

create index leads_location_id_idx on public.leads(location_id);
create index leads_status_idx on public.leads(status);
create index profiles_email_idx on public.profiles(email);

create or replace function public.set_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

create trigger locations_set_updated_at
before update on public.locations
for each row execute procedure public.set_updated_at();

create trigger profiles_set_updated_at
before update on public.profiles
for each row execute procedure public.set_updated_at();

create trigger leads_set_updated_at
before update on public.leads
for each row execute procedure public.set_updated_at();




create or replace view public.crm_leads_expanded as
select
  l.*,
  loc.name as location_name
from public.leads l
left join public.locations loc on loc.id = l.location_id;

create or replace view public.crm_tours_expanded as
select
  t.*,
  loc.name as location_name
from public.tours t
left join public.locations loc on loc.id = t.location_id;

create or replace view public.crm_messages_expanded as
select
  pm.*,
  loc.name as location_name
from public.parent_messages pm
left join public.locations loc on loc.id = pm.location_id;

alter table public.locations enable row level security;
alter table public.profiles enable row level security;
alter table public.leads enable row level security;
alter table public.tours enable row level security;
alter table public.parent_messages enable row level security;
alter table public.classrooms enable row level security;
alter table public.staff_assignments enable row level security;
alter table public.compliance_items enable row level security;

-- Test-mode policies for the static frontend. Tighten these before production.
create policy "locations_read_all" on public.locations for select using (true);
create policy "profiles_read_all" on public.profiles for select using (true);
create policy "leads_read_all" on public.leads for select using (true);
create policy "leads_insert_all" on public.leads for insert with check (true);
create policy "tours_read_all" on public.tours for select using (true);
create policy "messages_read_all" on public.parent_messages for select using (true);
create policy "classrooms_read_all" on public.classrooms for select using (true);
create policy "staff_read_all" on public.staff_assignments for select using (true);
create policy "compliance_read_all" on public.compliance_items for select using (true);

commit;
